function has_close_elements(numbers, threshold) {
    // Sort the array to easily find the closest pair
    const sorted = [...numbers].sort((a, b) => a - b);

    // Check adjacent elements in the sorted array
    for (let i = 0; i < sorted.length - 1; i++) {
        if (Math.abs(sorted[i] - sorted[i + 1]) < threshold) {
            return true;
        }
    }

    return false;
}
