function mean_absolute_deviation(numbers) {
    const n = numbers.length;
    if (n === 0) return 0;

    // Calculate the mean
    const sum = numbers.reduce((acc, val) => acc + val, 0);
    const mean = sum / n;

    // Calculate the mean absolute deviation
    const absDiffs = numbers.map(val => Math.abs(val - mean));
    const mad = absDiffs.reduce((acc, val) => acc + val, 0) / n;

    return mad;
}
