```javascript
function make_palindrome(string) {
    if (string === "") return "";

    // Find the longest palindromic suffix
    let n = string.length;
    for (let i = 0; i < n; i++) {
        // Check if substring from index i to end is a palindrome
        let substr = string.substring(i);
        if (isPalindrome(substr)) {
            // The prefix before this palindromic suffix is string.substring(0, i)
            let prefix = string.substring(0, i);
            let reversedPrefix = prefix.split('').reverse().join('');
            return string + reversedPrefix;
        }
    }

    // Fallback (should not reach here for non-empty strings)
    return string + string.slice(0, -1).split('').reverse().join('') + string[string.length - 1];
}

function isPalindrome(s) {
    let left = 0;
    let right = s.length - 1;
    while (left < right) {
        if (s[left] !== s[right]) return false;
        left++;
        right--;
    }
    return true;
}
