    let result = [numbers[0], numbers[1]];

    for (let i = 0; i < numbers.length; i++) {
        for (let j = i + 1; j < numbers.length; j++) {
            const diff = Math.abs(numbers[i] - numbers[j]);
            if (diff < minDiff) {
                minDiff = diff;
                result = [Math.min(numbers[i], numbers[j]), Math.max(numbers[i], numbers[j])];
