```javascript
function triples_sum_to_zero(l) {
    const n = l.length;
    if (n < 3) return false;

    // Sort the array to use two-pointer technique
    l.sort((a, b) => a - b);

    for (let i = 0; i < n - 2; i++) {
        // Skip duplicate values for the first element
        if (i > 0 && l[i] === l[i - 1]) continue;

        let left = i + 1;
        let right = n - 1;

        while (left < right) {
            const sum = l[i] + l[left] + l[right];

            if (sum === 0) {
                return true;
            } else if (sum < 0) {
                left++;
            } else {
                right--;
            }
        }
    }

    return false;
}
