function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Numbers that start with 1: 1 followed by any (n-1) digits -> 10^(n-1) numbers
    // Numbers that end with 1: any digit from 1-9 for first position, then any (n-2) digits, then 1 -> 9 * 10^(n-2) numbers
    // But we double-counted numbers that both start AND end with 1: 1 followed by any (n-2) digits and ending with 1 -> 10^(n-2) numbers

    const startsWithOne = Math.pow(10, n - 1);
    const endsWithOne = 9 * Math.pow(10, n - 2);
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    return startsWithOne + endsWithOne - bothStartAndEndWithOne;
}
