function match_parens(lst) {
    // Function to calculate the balance of a string.
    // It tracks the minimum balance encountered and the final balance.
    // A string is balanced if final balance is 0 and min balance never drops below 0.
    function getBalanceInfo(s) {
        let balance = 0;
        let minBalance = 0;
        for (let char of s) {
            if (char === '(') {
                balance++;
            } else {
                balance--;
            }
            minBalance = Math.min(minBalance, balance);
        }
        return { balance, minBalance };
    }

    const info1 = getBalanceInfo(lst[0]);
    const info2 = getBalanceInfo(lst[1]);

    // We can try two orders: lst[0] + lst[1] and lst[1] + lst[0]
    // For a concatenation to be balanced:
    // 1. The total balance must be 0.
    // 2. When appending the second string, the running balance must never drop below 0.

    // Check order 1: lst[0] then lst[1]
    // After processing lst[0], balance is info1.balance.
    // The minimum balance during lst[0] is info1.minBalance (which should be >= 0 for lst[0] to be valid on its own in context, but actually we need the combined string to be valid).
    // Actually, let's think about it differently.

    // For the combined string S = A + B to be balanced:
    // 1. totalBalance(A) + totalBalance(B) == 0
    // 2. For all prefixes of A, balance >= 0. (i.e., minBalance(A) >= 0)
    // 3. For all prefixes of B appended after A, the running balance must be >= 0.
    //    The running balance at any point in B is: totalBalance(A) + balance_in_B_so_far.
    //    So we need: totalBalance(A) + minBalance(B) >= 0.

    // Similarly for S = B + A:
    // 1. totalBalance(B) + totalBalance(A) == 0 (same condition)
    // 2. minBalance(B) >= 0
    // 3. totalBalance(B) + minBalance(A) >= 0

    const totalBalance = info1.balance + info2.balance;

    if (totalBalance !== 0) {
        return "No";
    }

    // Check order 1: lst[0] + lst[1]
    const order1Valid = info1.minBalance >= 0 && 
                        (info1.balance + info2.minBalance >= 0);

    // Check order 2: lst[1] + lst[0]
    const order2Valid = info2.minBalance >= 0 && 
                        (info2.balance + info1.minBalance >= 0);

    if (order1Valid || order2Valid) {
        return "Yes";
    } else {
        return "No";
    }
}
