function specialFilter(nums) {
    const oddDigits = new Set([1, 3, 5, 7, 9]);

    return nums.filter(num => {
        // Check if the number is greater than 10
        if (num <= 10) return false;

        // Get the absolute value to handle negative numbers
        const absNum = Math.abs(num);

        // Convert to string to get first and last digits
        const numStr = absNum.toString();
        const firstDigit = parseInt(numStr[0]);
        const lastDigit = parseInt(numStr[numStr.length - 1]);

        // Check if both first and last digits are odd
        return oddDigits.has(firstDigit) && oddDigits.has(lastDigit);
    }).length;
}
