```javascript
function get_max_triples(n) {
    // Generate the array a where a[i] = i*i - i + 1 for i from 1 to n
    const a = [];
    for (let i = 1; i <= n; i++) {
        a.push(i * i - i + 1);
    }

    // Count triples (i, j, k) with i < j < k such that a[i] + a[j] + a[k] is divisible by 3

    // First, let's find the pattern of a[i] mod 3
    // a[i] = i^2 - i + 1
    // Let's compute a[i] % 3 for different values of i % 3:
    // If i % 3 == 0: a[i] = 0 - 0 + 1 = 1 mod 3
    // If i % 3 == 1: a[i] = 1 - 1 + 1 = 1 mod 3
    // If i % 3 == 2: a[i] = 4 - 2 + 1 = 3 = 0 mod 3

    // So:
    // i % 3 == 0 => a[i] % 3 == 1
    // i % 3 == 1 => a[i] % 3 == 1
    // i % 3 == 2 => a[i] % 3 == 0

    // Let's count how many indices have each remainder:
    let count0 = 0; // a[i] % 3 == 0
    let count1 = 0; // a[i] % 3 == 1
    let count2 = 0; // a[i] % 3 == 2

    for (let i = 1; i <= n; i++) {
        const rem = (i * i - i + 1) % 3;
        if (rem === 0) count0++;
        else if (rem === 1) count1++;
        else count2++;
    }

    // We need a[i] + a[j] + a[k] ≡ 0 (mod 3)
    // Possible combinations of remainders (r1, r2, r3) such that r1 + r2 + r3 ≡ 0 (mod 3):
    // (0, 0, 0), (0, 1, 2), (1, 1, 1), (2, 2, 2)

    let triples = 0;

    // (0, 0, 0): choose 3 from count0
    if (count0 >= 3) {
        triples += count0 * (count0 - 1) * (count0 - 2) / 6;
    }

    // (1, 1, 1): choose 3 from count1
    if (count1 >= 3) {
        triples += count1 * (count1 - 1) * (count1 - 2) / 6;
    }

    // (2, 2, 2): choose 3 from count2
    if (count2 >= 3) {
        triples += count2 * (count2 - 1) * (count2 - 2) / 6;
    }

    // (0, 1, 2): choose one from each
    triples += count0 * count1 * count2;

    return triples;
}
