function bf(planet1, planet2) {
    const planets = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"];

    // Check if both planets are valid
    const idx1 = planets.indexOf(planet1);
    const idx2 = planets.indexOf(planet2);

    if (idx1 === -1 || idx2 === -1) {
        return [];
    }

    // Get the range between the two planets
    let start = Math.min(idx1, idx2);
    let end = Math.max(idx1, idx2);

    // Extract planets strictly between them
    const result = planets.slice(start + 1, end);

    return result;
}
