function double_the_difference(lst) {
    if (!lst || lst.length === 0) {
        return 0;
    }

    return lst.reduce((sum, num) => {
        // Ignore negative numbers and non-integers
        if (num < 0 || !Number.isInteger(num)) {
            return sum;
        }
        // Add square if the number is odd
        if (num % 2 !== 0) {
            return sum + num * num;
        }
        return sum;
    }, 0);
}
