function Strongest_Extension(class_name, extensions) {
    let strongest = null;
    let maxStrength = -Infinity;

    for (let ext of extensions) {
        let cap = 0;
        let sm = 0;
        for (let char of ext) {
            if (char >= 'A' && char <= 'Z') {
                cap++;
            } else if (char >= 'a' && char <= 'z') {
                sm++;
            }
        }
        let strength = cap - sm;
        if (strength > maxStrength) {
            maxStrength = strength;
            strongest = ext;
        }
    }

    return `${class_name}.${strongest}`;
}
