function right_angle_triangle(a, b, c) {
    // Sort the sides to identify the hypotenuse (longest side)
    const sides = [a, b, c].sort((x, y) => x - y);
    const [leg1, leg2, hypotenuse] = sides;

    // Check if it satisfies the Pythagorean theorem: a^2 + b^2 = c^2
    // Use a small epsilon for floating point comparison safety
    const epsilon = 1e-9;
    return Math.abs(leg1 * leg1 + leg2 * leg2 - hypotenuse * hypotenuse) < epsilon;
}
