```javascript
function do_algebra(operator, operand) {
    // We need to evaluate the expression respecting operator precedence.
    // Operators: +, -, *, //, **
    // Precedence (high to low): **, *, //, +, -

    // Create a copy of operands and operators to work with
    let ops = [...operator];
    let nums = [...operand];

    // Helper function to apply an operator to two numbers
    const applyOp = (op, a, b) => {
        switch(op) {
            case '+': return a + b;
            case '-': return a - b;
            case '*': return a * b;
            case '//': return Math.floor(a / b);
            case '**': return Math.pow(a, b);
            default: throw new Error('Unknown operator');
        }
    };

    // We'll use two stacks approach or convert to RPN (Reverse Polish Notation)
    // Let's use the shunting-yard algorithm to handle precedence

    const precedence = {
        '+': 1,
        '-': 1,
        '*': 2,
        '//': 2,
        '**': 3
    };

    // Convert infix to postfix (RPN)
    let outputQueue = [];
    let operatorStack = [];

    for (let i = 0; i < nums.length; i++) {
        // Push number to output queue
        outputQueue.push(nums[i]);

        // If not the last element, push operator to stack
        if (i < ops.length) {
            let op = ops[i];

            // While there is an operator at the top of the stack with greater or equal precedence
            // (for left-associative operators), pop it to output queue
            while (operatorStack.length > 0 && 
                   operatorStack[operatorStack.length - 1] !== '(' &&
                   ((precedence[op] <= precedence[operatorStack[operatorStack.length - 1]]) ||
                    (op === '**' && precedence[op] < precedence[operatorStack[operatorStack.length - 1]]))) {
                // For exponentiation, it's right-associative, so we only pop if strictly less
                // Actually, let me reconsider: ** is right-associative, others are left-associative

                let topOp = operatorStack[operatorStack.length - 1];

                if (op === '**') {
                    // Right associative: only pop if stack top has higher precedence
                    if (precedence[topOp] > precedence[op]) {
                        outputQueue.push(operatorStack.pop());
                    } else {
                        break;
                    }
                } else {
                    // Left associative: pop if stack top has greater or equal precedence
                    if (precedence[topOp] >= precedence[op]) {
                        outputQueue.push(operatorStack.pop());
                    } else {
                        break;
                    }
                }
            }

            operatorStack.push(op);
        }
    }

    // Pop all remaining operators to output queue
    while (operatorStack.length > 0) {
        outputQueue.push(operatorStack.pop());
    }

    // Evaluate RPN expression
    let evalStack = [];
    for (let token of outputQueue) {
        if (typeof token === 'number') {
            evalStack.push(token);
        } else {
            let b = evalStack.pop();
            let a = evalStack.pop();
            evalStack.push(applyOp(token, a, b));
        }
    }

    return evalStack[0];
}
