function solve(s) {
    const hasLetters = /[a-zA-Z]/.test(s);

    if (!hasLetters) {
        return s.split('').reverse().join('');
    }

    let result = '';
    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (/[a-zA-Z]/.test(char)) {
            if (char === char.toUpperCase()) {
                result += char.toLowerCase();
            } else {
                result += char.toUpperCase();
            }
        } else {
            result += char;
        }
    }

    return result;
}
